internalDeclarations.type:
∀ {P : Core.Problem} {pieces : CT2.PieceSystem P} {interfaces : CT2.InterfaceSystem pieces}
  (self : CT2.ContextSystem interfaces) {G : P.Ambient} (piece : pieces.Piece G),
  self.glue (self.currentContext piece) (self.abstract piece) = G

∀ {P : Core.Problem} {pieces : CT2.PieceSystem P} {interfaces : CT2.InterfaceSystem pieces}
  {contexts : CT2.ContextSystem interfaces} (self : CT2.ReplacementSystem contexts) {G : P.Ambient}
  (piece : pieces.Piece G) (candidate : self.Candidate piece),
  P.rank (contexts.glue (contexts.currentContext piece) (self.replacement piece candidate)) < P.rank G

∀ {P : Core.Problem} {Target : P.Ambient → Prop} {capability : CT2.Capability P Target}
  {ctx : Core.MinimalCounterexampleContext P Target} {input : CT2.Input capability ctx},
  CT2.DeletionWitness capability ctx input → ¬Target (capability.reductions.delete input.seed.piece).value

∀ {P : Core.Problem} {Target : P.Ambient → Prop} {capability : CT2.Capability P Target}
  {ctx : Core.MinimalCounterexampleContext P Target} {input : CT2.Input capability ctx},
  CT2.DeletionWitness capability ctx input → P.Baseline (capability.reductions.delete input.seed.piece).value

∀ {P : Core.Problem} {Target : P.Ambient → Prop} {capability : CT2.Capability P Target}
  {ctx : Core.MinimalCounterexampleContext P Target} {input : CT2.Input capability ctx}
  {candidate : capability.replacements.Candidate input.seed.piece}
  (self : CT2.ContextSeparator capability ctx input candidate),
  CT2.sourceObservation capability ctx input self.context ≠
    CT2.replacementObservation capability ctx input candidate self.context

formalDeclaration.type:
∀ {P : Core.Problem} {pieces : CT2.PieceSystem P} {interfaces : CT2.InterfaceSystem pieces}
  (self : CT2.ContextSystem interfaces) {G : P.Ambient} (piece : pieces.Piece G),
  self.glue (self.currentContext piece) (self.abstract piece) = G

∀ {P : Core.Problem} {pieces : CT2.PieceSystem P} {interfaces : CT2.InterfaceSystem pieces}
  {contexts : CT2.ContextSystem interfaces} (self : CT2.ReplacementSystem contexts) {G : P.Ambient}
  (piece : pieces.Piece G) (candidate : self.Candidate piece),
  P.rank (contexts.glue (contexts.currentContext piece) (self.replacement piece candidate)) < P.rank G

