∀ {P : Core.Problem} {S : CT3.Spec P} {_C : CT3.Capability S} {input : CT3.Input S}
  {_vector : CT3.ExactVectorState S input},
  (∀ (candidate : S.Candidate), ¬CT3.Compresses S input candidate) → CT3.UncompressibleExternalType S _C input _vector

formalDeclaration.type:
∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx),
  self.source.graph.Connected

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx),
  (Graph.PackedBoundariedGluing.Piece.pack boundaries self.source).lexRank < Graph.PackedFiniteObject.lexRank ctx.G

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom) (boundary : T),
  Graph.PackedBoundariedGluing.Piece.boundaryDegree boundaries self.piece boundary =
    Graph.PackedBoundariedGluing.Piece.boundaryDegree boundaries atom.source boundary

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom)
  (outside : Graph.PackedBoundariedGluing.Context T),
  input.Target (Graph.PackedBoundariedGluing.glue boundaries self.piece outside) →
    input.Target (Graph.PackedBoundariedGluing.glue boundaries atom.source outside)

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  ¬input.Target (Graph.PackedBoundariedGluing.Piece.pack boundaries self.piece)

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  Graph.PackedBoundariedGluing.Piece.InternalBaseline boundaries input.minimumDegree self.piece

∀ {input : Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  {ctx : Core.MinimalCounterexampleContext input.problem input.Target}
  {atom : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (self : Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  self.piece.LexSmaller atom.source

internalDeclarations.type:
∀ {P : Core.Problem} {S : CT4.Spec P} {capability : CT4.Capability S} {input : CT4.Input P}
  (self : CT4.AssignmentState S capability input) (demand : S.Demand),
  self.assigned demand = none → CT4.MissingAt S input demand

∀ {P : Core.Problem} {S : CT4.Spec P} {capability : CT4.Capability S} {input : CT4.Input P}
  (self : CT4.AssignmentState S capability input) (demand : S.Demand) (payer : S.Payer),
  self.assigned demand = some payer → S.Eligible input demand payer

∀ {P : Core.Problem} (capability : CT12.Capability P) {input : CT12.Input capability}
  (r : CT12.ExecutionResult capability input),
  CT12.Graph.ValidTrace capability (CT12.ExecutionResult.trace capability r)

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input},
  CT15.FullRankState S capability input rank → rank.value = CT15.targetRank S capability

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input},
  CT15.FullRankState S capability input rank → ∀ (coordinate : S.Coordinate), ¬S.TargetDependent input coordinate

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input} {full : CT15.FullRankState S capability input rank}
  (self : CT15.LedgerState S capability input full), self.entries = CT15.ledgerEntries S capability input

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input} {full : CT15.FullRankState S capability input rank}
  (self : CT15.LedgerState S capability input full), self.total = CT15.ledgerTotal S capability input

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input} {full : CT15.FullRankState S capability input rank}
  {ledger : CT15.LedgerState S capability input full},
  S.capacity input < ledger.total → CT15.C4Certificate S capability input ledger

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input} {full : CT15.FullRankState S capability input rank}
  {ledger : CT15.LedgerState S capability input full},
  ledger.total ≤ S.capacity input → CT15.FullRankLedgerResidual S capability input ledger

∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {_invocation : CT17.Input S C context} (self : CT17.IncompatibilityResidual S C context _invocation),
  ¬S.Compatible context self.target self.offset

∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {invocation : CT17.Input S C context} {_compatible : CT17.CompatibleState S C context invocation},
  CT17.FiniteScaleState S C context invocation _compatible → invocation.scale ≤ C.finiteScaleLimit

∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {invocation : CT17.Input S C context} {_compatible : CT17.CompatibleState S C context invocation},
  CT17.OrbitScaleState S C context invocation _compatible → C.finiteScaleLimit < invocation.scale

∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {invocation : CT17.Input S C context} {_compatible : CT17.CompatibleState S C context invocation},
  invocation.scale ≤ C.finiteScaleLimit → CT17.FiniteScaleState S C context invocation _compatible

∀ {P : Core.Problem} {S : CT17.Spec P} {C : CT17.Capability S} {context : Core.BranchContext P}
  {invocation : CT17.Input S C context} {_compatible : CT17.CompatibleState S C context invocation},
  C.finiteScaleLimit < invocation.scale → CT17.OrbitScaleState S C context invocation _compatible

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {finite : CT17.FiniteScaleState S capability ctx input compatible}
  (self : CT17.ExhaustedCertificate S capability ctx input) (position : S.Position input.scale),
  ¬CT17.Survives S capability ctx input position

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {finite : CT17.FiniteScaleState S capability ctx input compatible}
  (self : CT17.SurvivorEnumeration S capability ctx input finite) (position : S.Position input.scale),
  CT17.Survives S capability ctx input position → position ∈ self.survivors

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {finite : CT17.FiniteScaleState S capability ctx input compatible}
  (self : CT17.SurvivorEnumeration S capability ctx input finite),
  ∀ position ∈ self.survivors, CT17.Survives S capability ctx input position

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {finite : CT17.FiniteScaleState S capability ctx input compatible}
  (self : CT17.SurvivorResidual S capability ctx input), self.enumeration.survivors = self.first :: self.remaining

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {orbit : CT17.OrbitScaleState S capability ctx input compatible}
  (self : CT17.OrbitResidual S capability ctx input orbit), CT17.OrbitAvoids S capability ctx input

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {orbit : CT17.OrbitScaleState S capability ctx input compatible}
  (self : CT17.OrbitResidual S capability ctx input orbit),
  self.values = List.map (S.orbitValue ctx input.scale) capability.offsets.orderedValues

∀ {P : Core.Problem} {S : CT17.Spec P} {capability : CT17.Capability S} {ctx : Core.BranchContext P}
  {input : CT17.Input S capability ctx} {compatible : CT17.CompatibleState S capability ctx input}
  {orbit : CT17.OrbitScaleState S capability ctx input compatible}
  (self : CT17.TargetHitCertificate S capability ctx input orbit),
  S.orbitValue ctx input.scale self.offset = S.targetValue self.target
